import { useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { workScheduleService as accountService } from "@/api/workScheduleService";
import { queryKeys } from '@/lib/queryKeys';
import { leaveService } from "@/api/leaveService";
import { getApiErrorMessage } from "@/api/app/apiError";
export function useWorkScheduleMutations(year: number, month: number) {
  const queryClient = useQueryClient();

  const updateMutation = useMutation({
    mutationFn: accountService.updateWorkDay,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to update schedule')),
  });

  const submitMutation = useMutation({
    mutationFn: (monthId: string) => accountService.submitSchedule(monthId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.monthsBase() });
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to submit schedule')),
  });

  const approveMutation = useMutation({
    mutationFn: (monthId: string) => accountService.approveSchedule(monthId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to approve')),
  });

  const rejectMutation = useMutation({
    mutationFn: ({ monthId, notes }: { monthId: string; notes: string }) =>
      accountService.rejectSchedule(monthId, notes),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to reject')),
  });

  const importMutation = useMutation({
    mutationFn: accountService.importWorkSchedule,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.monthsBase() });
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to import schedule')),
  });

  const importWeekMutation = useMutation({
    mutationFn: accountService.importWeek,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.monthsBase() });
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to import week')),
  });

  const clearMutation = useMutation({
    mutationFn: (monthId: string) => accountService.clearWorkSchedule(monthId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.monthsBase() });
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to clear schedule')),
  });

  const unfreezeMutation = useMutation({
    mutationFn: (monthId: string) => accountService.unfreezeSchedule(monthId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.monthsBase() });
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to unfreeze schedule')),
  });

  const leaveMutation = useMutation({
    mutationFn: leaveService.createLeave,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
      queryClient.invalidateQueries({ queryKey: ['leave'] }) // leaveQueryKeys.all — cross-feature invalidation
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to create leave request')),
  });

  return {
    updateMutation,
    submitMutation,
    approveMutation,
    rejectMutation,
    importMutation,
    importWeekMutation,
    clearMutation,
    unfreezeMutation,
    leaveMutation,
  };
}
